import { useState, useEffect } from "react";
import Sidebar from "./components/Sidebar";
import Topbar from "./components/Topbar";
import DashboardPage from "./pages/DashboardPage";
import AlertsPage from "./pages/AlertsPage";
import LogsPage from "./pages/LogsPage";
import InvestigationPage from "./pages/InvestigationPage";
import { MOCK_ALERTS } from "./data/mockAlerts";
import { api } from "./services/api";

export default function App() {
  const [page, setPage] = useState("dashboard");
  const [search, setSearch] = useState("");
  const [selectedAlert, setSelectedAlert] = useState(null);
  const [alerts, setAlerts] = useState(MOCK_ALERTS); // mock data as fallback
  const [loading, setLoading] = useState(true);
  const [usingMock, setUsingMock] = useState(false);

  useEffect(() => {
    api.getAlerts({ limit: 50 })
      .then((res) => {
        // If real data came back and has items, use it
        if (res.data && res.data.length > 0) {
          setAlerts(res.data);
          setUsingMock(false);
        } else {
          // Wazuh returned empty — no attacks yet, keep mock
          setUsingMock(true);
        }
      })
      .catch(() => {
        // Backend offline — silently fall back to mock data
        setUsingMock(true);
      })
      .finally(() => setLoading(false));
  }, []);

  function navigate(p) {
    setPage(p);
    setSelectedAlert(null);
  }

  const pageContent = () => {
    switch (page) {
      case "dashboard":
        return (
          <DashboardPage
            alerts={alerts}
            setPage={navigate}
            setSelectedAlert={setSelectedAlert}
          />
        );
      case "alerts":
        return (
          <AlertsPage
            alerts={alerts}
            selectedAlert={selectedAlert}
            setSelectedAlert={setSelectedAlert}
          />
        );
      case "logs":
        return <LogsPage alerts={alerts} />;
      case "investigation":
        return <InvestigationPage />;
      default:
        return null;
    }
  };

  return (
    <div style={{
      display: "flex",
      height: "100vh",
      overflow: "hidden",
      fontFamily: "var(--font-mono)",
      background: "var(--bg)",
    }}>
      <Sidebar page={page} setPage={navigate} />

      <div style={{ flex: 1, display: "flex", flexDirection: "column", overflow: "hidden", minWidth: 0 }}>
        <Topbar search={search} setSearch={setSearch} />

        {/* Banner when using mock data */}
        {usingMock && !loading && (
          <div style={{
            background: "rgba(255,140,0,0.1)",
            border: "1px solid rgba(255,140,0,0.3)",
            borderRadius: 0,
            padding: "6px 24px",
            fontSize: 11,
            color: "#ff8c00",
            fontFamily: "var(--font-mono)",
            display: "flex",
            alignItems: "center",
            gap: 8,
          }}>
            <span>⚠</span>
            Backend connected but no real alerts yet — showing mock data.
            Simulate attacks to see real alerts appear here.
          </div>
        )}

        {/* Loading state */}
        {loading && (
          <div style={{
            padding: "6px 24px",
            fontSize: 11,
            color: "var(--accent)",
            fontFamily: "var(--font-mono)",
            borderBottom: "1px solid var(--border)",
            display: "flex",
            alignItems: "center",
            gap: 8,
          }}>
            <div style={{
              width: 6, height: 6,
              background: "var(--accent)",
              borderRadius: "50%",
              animation: "pulse 1s infinite",
            }} />
            Connecting to Wazuh...
          </div>
        )}

        <div style={{ flex: 1, overflow: "hidden", background: "var(--bg)" }}>
          {pageContent()}
        </div>
      </div>
    </div>
  );
}
